const __pageData = JSON.parse('{"title":"桌面开发选型终极指南","description":"建立桌面开发方案的多维度形式化评估模型与生命周期成本框架，绘制 2026 年桌面技术全景对比矩阵与选型决策树，深度探讨 Electron 向 Tauri 的迁移策略，并前瞻 WebAssembly、AI 辅助与 AR/VR 驱动的桌面开发未来。","frontmatter":{"title":"桌面开发选型终极指南","description":"建立桌面开发方案的多维度形式化评估模型与生命周期成本框架，绘制 2026 年桌面技术全景对比矩阵与选型决策树，深度探讨 Electron 向 Tauri 的迁移策略，并前瞻 WebAssembly、AI 辅助与 AR/VR 驱动的桌面开发未来。","date":"2026-05-01T00:00:00.000Z","tags":["desktop","Electron","Tauri","Flutter","React Native","Wails","Neutralinojs","selection-guide","comparison","migration","WebAssembly","AI"],"category":"engineering"},"headers":[],"relativePath":"desktop-development/08-desktop-development-selection-guide.md","filePath":"desktop-development/08-desktop-development-selection-guide.md","lastUpdated":1777741461000}');
